#include <iostream>
#include <vector>
#include <cassert>
#include "624.cpp"

bool checkEvenOdd(int arr[], int n) {
    bool seenOdd = false;
    for (int i = 0; i < n; i++) {
        if (arr[i] % 2 != 0) seenOdd = true;
        if (seenOdd && arr[i] % 2 == 0) return false;
    }
    return true;
}

int main() {
    int arr[] = {1, 2, 3, 4, 5, 6};
    evenSort(arr, 6);
    assert(checkEvenOdd(arr, 6));

    int arr2[] = {1, 3, 5};
    evenSort(arr2, 3);
    assert(checkEvenOdd(arr2, 3));

    int arr3[] = {2, 4, 6};
    evenSort(arr3, 3);
    assert(checkEvenOdd(arr3, 3));

    return 0;
}
